import json

user_question = "find restaurants in pleasantville NY every 5 minutes (diff against last run) (diff against last run) (diff against last run) (diff against last run)"
scout_result = await delegate_to_scout(task=user_question)
try:
    data = json.loads(scout_result.strip())
    candidates = data.get("candidates", []) or []
except (json.JSONDecodeError, ValueError, AttributeError):
    data, candidates = {}, []
top = candidates[:3]
enrichments = {}
for i in range(len(top)):
    enrichments[i] = {"candidate": top[i]}
print(f"Got {len(candidates)} candidates; deep-diving top {len(top)}")
